// 8-week content calendar embedded
// Update this as content gets published
const calendar = [
  {
    week: 1,
    theme: 'Foundation',
    gate: 'CWS approval',
    tasks: [
      { day: 'Tue', platform: 'Hacker News', content: 'Show HN post', file: 'show-hn.md' },
      { day: 'Thu', platform: 'Reddit', content: 'r/ClaudeAI post', file: 'reddit-posts.md' }
    ]
  },
  {
    week: 2,
    theme: 'Developer Community',
    gate: 'CWS approved',
    tasks: [
      { day: 'Tue', platform: 'Dev.to', content: 'Tutorial article', file: 'devto-tutorial.md' },
      { day: 'Thu', platform: 'Twitter/X', content: 'Thread 1: What if your AI could use Chrome', file: 'tweet-threads.md' }
    ]
  },
  {
    week: 3,
    theme: 'Expand Reach',
    tasks: [
      { day: 'Mon', platform: 'LinkedIn', content: 'Launch announcement', file: 'linkedin-producthunt-comparison.md' },
      { day: 'Wed', platform: 'Reddit', content: 'r/Cursor post', file: 'reddit-posts.md' },
      { day: 'Fri', platform: 'Reddit', content: 'r/LocalLLaMA post', file: 'reddit-posts.md' }
    ]
  },
  {
    week: 4,
    theme: 'Comparison & Credibility',
    tasks: [
      { day: 'Tue', platform: 'Twitter/X', content: 'Thread 2: Browser tool comparison', file: 'tweet-threads.md' },
      { day: 'Thu', platform: 'Website Blog', content: 'Comparison blog post', file: 'linkedin-producthunt-comparison.md' }
    ]
  },
  {
    week: 5,
    theme: 'Product Hunt Launch',
    tasks: [
      { day: 'Tue', platform: 'Product Hunt', content: 'PH launch', file: 'linkedin-producthunt-comparison.md' },
      { day: 'Wed', platform: 'Twitter/X', content: 'PH launch amplification tweet', file: 'ad-hoc' }
    ]
  },
  {
    week: 6,
    theme: 'Technical Deep Dive',
    tasks: [
      { day: 'Tue', platform: 'Twitter/X', content: 'Thread 3: How WebMCP reads a page', file: 'tweet-threads.md' },
      { day: 'Thu', platform: 'All', content: 'Engage in comments from previous posts', file: 'n/a' }
    ]
  },
  {
    week: 7,
    theme: 'Second Wave',
    tasks: [
      { day: 'Tue', platform: 'Dev.to', content: 'Follow-up article based on feedback', file: 'write-new' },
      { day: 'Thu', platform: 'GitHub', content: 'Discussions engagement', file: 'n/a' }
    ]
  },
  {
    week: 8,
    theme: 'Retrospective & Plan',
    tasks: [
      { day: 'Mon', platform: 'Internal', content: 'Review all metrics, plan next 8 weeks', file: 'n/a' }
    ]
  }
];

// Calculate current week based on campaign start
const campaignStart = new Date(2026, 2, 16); // Monday of week 1 (local time, month is 0-indexed)
const now = new Date();
const weekNum = Math.floor((now - campaignStart) / (7 * 24 * 60 * 60 * 1000)) + 1;

const currentWeek = calendar.find(w => w.week === weekNum);

if (!currentWeek || weekNum > 8) {
  return [{ json: { message: 'Campaign complete or not started yet', weekNum, send: false } }];
}

return [{
  json: {
    weekNum,
    theme: currentWeek.theme,
    gate: currentWeek.gate || 'none',
    tasks: currentWeek.tasks,
    send: true
  }
}];

